module RefModule(clk, rst, en, D, Q);
    input clk, rst, en;
    input [7:0] D;
    output reg [7:0] Q;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            Q <= 8'b00000000;
        else if (en)
            Q <= D;
    end
endmodule
